func drsObjectFromInternal(r *http.Request, object *drs_support.InternalDrsObject, expand bool) DrsObject {
	var accessMethods []AccessMethod
	if serviceContext, ok := DrsServiceContextFromContext(r.Context()); ok && serviceContext != nil {
		accessMethods = accessMethodsFromInternal(drs_support.BuildAccessMethods(serviceContext.DrsConfig, object))
	}

	response := DrsObject{
		Id:            object.Id,
		Name:          object.AbsolutePath,
		SelfUri:       buildSelfURI(r, object.Id),
		Size:          object.Size,
		CreatedTime:   object.CreatedTime,
		UpdatedTime:   object.UpdatedTime,
		Version:       object.Version,
		MimeType:      object.MimeType,
		AccessMethods: accessMethods,
		Description:   object.Description,
		Aliases:       append([]string(nil), object.Aliases...),
	}

	if object.Checksum != nil && object.Checksum.Value != "" {
		response.Checksums = []Checksum{{
			Checksum: object.Checksum.Value,
			Type_:    object.Checksum.Type,
		}}
	} else {
		response.Checksums = []Checksum{}
	}

	if expand && len(object.Contents) > 0 {
		response.Contents = make([]ContentsObject, 0, len(object.Contents))
		for _, entry := range object.Contents {
			response.Contents = append(response.Contents, ContentsObject{
				Name:   entry.Name,
				Id:     entry.ID,
				DrsUri: buildContentsDrsURIs(r, entry.ID),
			})
		}
	}

	return response
}

func accessMethodsFromInternal(methods []drs_support.DrsAccessMethod) []AccessMethod {
	if len(methods) == 0 {
		return nil
	}

	response := make([]AccessMethod, 0, len(methods))
	for _, method := range methods {
		accessMethod := AccessMethod{
			Type_:     method.Type,
			AccessId:  method.AccessID,
			Cloud:     method.Cloud,
			Region:    method.Region,
			Available: method.Available,
		}

		if method.URL != "" {
			accessMethod.AccessUrl = &AllOfAccessMethodAccessUrl{
				Url: method.URL,
			}
		}

		if len(method.SupportedAuthTypes) > 0 || len(method.BearerAuthIssuers) > 0 {
			accessMethod.Authorizations = &AllOfAccessMethodAuthorizations{
				SupportedTypes:    append([]string(nil), method.SupportedAuthTypes...),
				BearerAuthIssuers: append([]string(nil), method.BearerAuthIssuers...),
			}
		}

		response = append(response, accessMethod)
	}

	return response
}

func buildSelfURI(r *http.Request, objectID string) string {
	host := strings.TrimSpace(r.Host)
	if host == "" {
		return ""
	}

	return fmt.Sprintf("drs://%s/%s", host, objectID)
}

func buildContentsDrsURIs(r *http.Request, objectID string) []string {
	objectID = strings.TrimSpace(objectID)
	if objectID == "" {
		return nil
	}

	selfURI := buildSelfURI(r, objectID)
	if selfURI == "" {
		return nil
	}

	return []string{selfURI}
}

func authorizationsFromConfig(objectID string, drsConfig *drs_support.DrsConfig) Authorizations {
	response := Authorizations{
		DrsObjectId:    strings.TrimSpace(objectID),
		SupportedTypes: []string{"BasicAuth", "BearerAuth"},
	}

	if issuer := bearerAuthIssuerFromConfig(drsConfig); issuer != "" {
		response.BearerAuthIssuers = []string{issuer}
	}

	return response
}

func bulkAuthorizationsFromIDs(filesystem RouteFileSystem, drsConfig *drs_support.DrsConfig, objectIDs []string) (*InlineResponse2002, error) {
	resolved := make([]Authorizations, 0, len(objectIDs))
	missingIDs := make([]string, 0)

	for _, objectID := range objectIDs {
		if _, err := drs_support.GetDrsObjectByID(filesystem, objectID); err != nil {
			if strings.Contains(err.Error(), "not found") {
				missingIDs = append(missingIDs, objectID)
				continue
			}

			return nil, fmt.Errorf("resolve DRS object %q: %w", objectID, err)
		}

		resolved = append(resolved, authorizationsFromConfig(objectID, drsConfig))
	}

	response := &InlineResponse2002{
		Summary: &Summary{
			Requested:  int32(len(objectIDs)),
			Resolved:   int32(len(resolved)),
			Unresolved: int32(len(missingIDs)),
		},
		ResolvedDrsObject: resolved,
	}

	if len(missingIDs) > 0 {
		unresolved := []UnresolvedInner{{
			ErrorCode: http.StatusNotFound,
			ObjectIds: append([]string(nil), missingIDs...),
		}}
		response.UnresolvedDrsObjects = &unresolved
	}

	return response, nil
}

func normalizedBulkObjectIDs(objectIDs []string) []string {
	resolved := make([]string, 0, len(objectIDs))
	for _, objectID := range objectIDs {
		objectID = strings.TrimSpace(objectID)
		if objectID == "" {
			continue
		}
		resolved = append(resolved, objectID)
	}

	return resolved
}

func validateConfiguredHTTPSProvider(drsConfig *drs_support.DrsConfig) error {
	if drsConfig == nil || !drsConfig.HttpsAccessMethodSupported {
		return nil
	}

	switch drs_support.EffectiveHTTPSAccessProvider(drsConfig.HttpsAccessImplementation) {
	case drs_support.HTTPSProviderIRODSGoREST, drs_support.HTTPSProviderIRODSHTTPSAPI:
		return nil
	default:
		return fmt.Errorf("unsupported https access provider %q", drsConfig.HttpsAccessImplementation)
	}
}

func bearerAuthIssuerFromConfig(drsConfig *drs_support.DrsConfig) string {
	if drsConfig == nil {
		return ""
	}

	baseURL := strings.TrimRight(strings.TrimSpace(drsConfig.OidcUrl), "/")
	if baseURL == "" {
		return ""
	}

	realm := strings.TrimSpace(drsConfig.OidcRealm)
	if realm == "" {
		return baseURL
	}

	return baseURL + "/realms/" + neturl.PathEscape(realm)
}
